import { useState, useEffect, useCallback } from "react";
import axios from "axios";
import "./styles/global.css";

// Importação dos componentes
import Navbar      from "./components/Navbar";
import FormPanel   from "./components/FormPanel";
import Toast       from "./components/Toast";
import Footer      from "./components/Footer";
import LandingPage from "./components/LandingPage";

import { EMPTY_FORM } from "./constants";

const API_URL = "http://localhost:8080/agendamento";

export default function App() {
  const handleEdit = (appt) => {
    setForm({ name: appt.name, service: appt.service, date: appt.date, time: appt.time });
    setEditingId(appt.id);
  };

  // TELA DO ADMINISTRADOR
  if (view === "admin") {
    return (
      <>
        <AdminDashboard 
          appointments={appointments}
          onEdit={handleEdit}
          onDeleteRequest={setDeleteTarget}
          onGoHome={() => setView("landing")}
          editingId={editingId}
          form={form}
          setForm={setForm}
          onSubmit={handleSubmit}
          onCancel={() => {setForm(EMPTY_FORM); setEditingId(null);}}
        />
        {/* Modal de confirmação de exclusão */}
        <DeleteModal
          target={deleteTarget}
          onConfirm={handleDelete}
          onCancel={() => setDeleteTarget(null)}
        />
        <Toast toast={toast} />
      </>
    );
  }

  // RENDERIZAÇÃO DA LANDING PAGE
  if (view === "landing") {
    return <LandingPage onNavigate={() => setView("schedule")} />;
  }

  // RENDERIZAÇÃO DO SISTEMA DE AGENDAMENTO (CLIENTE)
  return (
    <div className="animate-reveal" style={{ background: '#000', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>

      <Navbar onGoHome={() => setView("landing")} />

      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '40px 20px' }}>

        {/* FORMULÁRIO DE AGENDAMENTO CENTRALIZADO */}
        <FormPanel
          form={form}
          setForm={setForm}
          editing={false} // Cliente nunca edita aqui
          onSubmit={handleSubmit}
          onCancel={() => setForm(EMPTY_FORM)}
        />

        {/* FRASE DE IMPACTO - O "CAPRICHO" NO DESIGN */}
        <div style={{ marginTop: '60px', textAlign: 'center', maxWidth: '800px' }}>
          <div style={{ height: '1px', width: '60px', background: 'var(--amarelo)', margin: '0 auto 20px' }}></div>

          <h2 style={{ 
            fontFamily: 'Cormorant Garamond, serif', 
            fontSize: 'clamp(32px, 5vw, 64px)', 
            color: 'white',
            fontWeight: '300',
            fontStyle: 'italic',
            lineHeight: '1.1',
            letterSpacing: '1px',
            margin: 0
          }}>
            A Melhor <span style={{ color: 'var(--amarelo)', fontWeight: '700' }}>Barbearia</span> <br />
            da Região
          </h2>

          <p style={{ 
            color: 'rgba(255,255,255,0.4)', 
            textTransform: 'uppercase', 
            letterSpacing: '4px', 
            fontSize: '12px', 
            marginTop: '20px' 
          }}>
            Tradição • Precisão • Estilo
          </p>
        </div>

      </main>

      <Footer />
      <Toast toast={toast} />
    </div>
  );
}
